UPDATE kings SET bio_hy = 'Ասորական Սարգոն II-ի ավերիչ արշավանքից հետո ինքնասպան եղավ։ Նրա պարտությունը նշանավորեց Ուրարտուի անկման սկիզբը։' WHERE id = 6;
UPDATE kings SET bio_hy = 'Ժամանակավորապես վերականգնեց թագավորությունը ասորական արշավանքների ազդեցությունից հետո։ Ղեկավարեց կայունացման ջանքերը։' WHERE id = 7;
UPDATE kings SET bio_hy = 'Ուրարտուի վաղ շրջանի մեծ շինարար թագավոր։ Կառուցեց Թեյշեբաինի ամրոցը՝ ռազմա-վարչական կարևոր կենտրոն։' WHERE id = 8;
UPDATE kings SET bio_hy = 'Վաղ շրջանի հայտնի թագավոր։ Ուրարտուն ձգտեց դիմադրել մեդական ու սկյութական ուժերի ճնշմանը։' WHERE id = 9;

