UPDATE kings SET bio_hy = 'Վերջին Արտաշեսյան թագավոր։ Թագավորությունը ճնշված էր Հռոմի ու Պարթիացիների անդադար մրցակցությամբ ու ճնշումով։' WHERE id = 18;

