UPDATE kings SET bio_hy = 'Արիասիրտ ռազմական թագավոր։ Պայքարեց Հռոմի ու Պարսկաստանի դեմ՝ պաշտպանելով Հայաստանի ինքնիշխանությունը երկու կայսրությունների միջև։' WHERE id = 22;
