UPDATE kings SET bio_hy = 'Մայրաքաղաքը տեղափոխեց Կարս։ Արաբական արշավանքներից հետո վերականգնեց երկիրը ու ընդլայնեց թագավորության սահմանները։' WHERE id = 26;
