UPDATE kings SET bio_hy = 'Բագրատունյաց թագավորության ծաղկման գագաթնակետ։ Անին 100.000-ից ավելի բնակչով դարձավ համաշխարհային նշանավոր մայրաքաղաք։' WHERE id = 28;
