UPDATE kings SET bio_hy = 'Կռվեց Մամլուքների դեմ՝ ձգտելով պաշտպանել Կիլիկիան։ Թագավորությունն ապրեց ծանր ճնշում ու ռազմական անկայունություն։' WHERE id = 34;
UPDATE kings SET bio_hy = 'Կիլիկիայի Հայկական Թագավորության վերջին թագավոր։ 1375 թ. Մամլուքները գրավեցին Սիս մայրաքաղաքն ու վերջ տվեցին հայկական Կիլիկիային։' WHERE id = 35;
